139	func itoa(n int) string {
140		if n == 0 {
141			return "0"
142		}
143		s := ""
144		neg := n < 0
145		if neg {
146			n = -n
147		}
148		for n > 0 {
149			s = string(rune('0'+n%10)) + s
150			n /= 10
151		}
152		if neg {
153			s = "-" + s
154		}
155		return s
156	}
