158	// TestExecuteBead_MergeDefault_NoGates verifies the merge-by-default contract:
159	// when the agent succeeds and produces changes with no required gates defined,
160	// the orchestrator merges the result.
161	func TestExecuteBead_MergeDefault_NoGates(t *testing.T) {
162		const beadID = "ddx-gate-test-01"
163		const specID = "FEAT-GATETEST"
164	
165		projectRoot := setupGateTestProjectRoot(t)
166		wtPath := t.TempDir()
167		setupGateTestWorktree(t, wtPath, beadID, specID, false, 0)
168	
169		res := &ExecuteBeadResult{
170			BeadID:    beadID,
171			BaseRev:   "aaa0000000000001",
172			ResultRev: "bbb0000000000001", // different → agent made commits
173			ExitCode:  0,
174			Outcome:   ExecuteBeadOutcomeTaskSucceeded,
175		}
176	
177		orch := &gateTestOrchestratorGitOps{}
178		advancer := &gateTestLandingAdvancer{}
179		landing, err := LandBeadResult(projectRoot, res, orch, BeadLandingOptions{
180			WtPath:          wtPath,
181			GovernIDs:       []string{specID},
182			LandingAdvancer: advancer.advance,
183		})
184		if err != nil {
185			t.Fatalf("LandBeadResult returned error: %v", err)
186		}
187		ApplyLandingToResult(res, landing)
188	
189		if res.Outcome != "merged" {
190			t.Errorf("expected outcome=merged, got %q (reason=%q)", res.Outcome, res.Reason)
191		}
192		if !advancer.called {
193			t.Error("expected LandingAdvancer to be called for the merge-by-default path")
194		}
195		if orch.preserveRef != "" {
196			t.Errorf("expected no preserve ref, got %q", orch.preserveRef)
197		}
198		if res.RequiredExecSummary != "skipped" {
199			t.Errorf("expected required_exec_summary=skipped (no gates), got %q", res.RequiredExecSummary)
200		}
201	}
