18	// runScriptFn executes a directive file against opts.WorkDir using real filesystem
19	// and git operations. The directive file path is taken from opts.Model (if it is
20	// a readable file) or from opts.PromptFile as a fallback.
21	func runScriptFn(r *Runner, opts RunOptions) (*Result, error) {
22		start := time.Now()
23	
24		// Resolve directive file: opts.Model first, then opts.PromptFile.
25		directivePath := opts.Model
26		if directivePath == "" || !isReadableFile(directivePath) {
27			if opts.PromptFile != "" {
28				directivePath = opts.PromptFile
29			}
30		}
31		if directivePath == "" {
32			return nil, fmt.Errorf("script harness: no directive file (set --model or --prompt-file)")
33		}
34	
35		data, err := os.ReadFile(directivePath)
36		if err != nil {
37			return nil, fmt.Errorf("script harness: read directive file %s: %w", directivePath, err)
38		}
39	
40		workDir := opts.WorkDir
41		if workDir == "" {
42			workDir = "."
43		}
44	
45		var outputLines []string
46		exitCode := 0
47		var execErr error
48	
49		directives := parseDirectives(string(data))
50	
51		// Build env interpolation map from Correlation.
52		envMap := map[string]string{
53			"DDX_BEAD_ID":         "",
54			"DDX_ATTEMPT_ID":      "",
55			"DDX_WORKER_ID":       "",
56			"DDX_SESSION_LOG_DIR": opts.SessionLogDir,
57		}
58		if opts.Correlation != nil {
59			if v, ok := opts.Correlation["bead_id"]; ok {
60				envMap["DDX_BEAD_ID"] = v
61			}
62			if v, ok := opts.Correlation["attempt_id"]; ok {
63				envMap["DDX_ATTEMPT_ID"] = v
64			}
65			if v, ok := opts.Correlation["worker_id"]; ok {
66				envMap["DDX_WORKER_ID"] = v
67			}
68		}
69		expand := func(s string) string {
70			return os.Expand(s, func(key string) string {
71				return envMap[key]
72			})
73		}
74	
75		for i, d := range directives {
76			verb := d[0]
77			args := d[1:]
78	
79			switch verb {
80			case "no-op":
81				outputLines = append(outputLines, "no-op")
82	
83			case "set-exit":
84				if len(args) < 1 {
85					execErr = fmt.Errorf("script harness: set-exit requires an argument")
86					goto done
87				}
88				n, err := strconv.Atoi(args[0])
89				if err != nil {
90					execErr = fmt.Errorf("script harness: set-exit: invalid code %q", args[0])
91					goto done
92				}
93				exitCode = n
94	
95			case "sleep-ms":
96				if len(args) < 1 {
97					execErr = fmt.Errorf("script harness: sleep-ms requires an argument")
98					goto done
99				}
100				n, err := strconv.Atoi(args[0])
101				if err != nil {
102					execErr = fmt.Errorf("script harness: sleep-ms: invalid duration %q", args[0])
103					goto done
104				}
105				time.Sleep(time.Duration(n) * time.Millisecond)
106	
107			case "fail-during":
108				if len(args) < 1 {
109					execErr = fmt.Errorf("script harness: fail-during requires an argument")
110					goto done
111				}
112				n, err := strconv.Atoi(args[0])
113				if err != nil {
114					execErr = fmt.Errorf("script harness: fail-during: invalid index %q", args[0])
115					goto done
116				}
117				if i == n {
118					execErr = fmt.Errorf("script harness: synthetic failure at directive %d", i)
119					goto done
120				}
121	
122			case "append-line":
123				if len(args) < 2 {
124					execErr = fmt.Errorf("script harness: append-line requires path and text")
